const OFFICIAL = '1-D,2-A,3-C,4-B,5-B,6-B,7-A,8-D,9-D,10-B,11-D,12-A,13-C,14-B,15-B,16-A,17-D,18-A,19-C,20-C,21-A,22-B,23-B,24-B,25-B,26-B,27-C,28-B,29-B,30-C,31-B,32-B,33-D,34-D,35-C,36-C,37-A,38-D,39-C,40-B,41-C,42-B,43-B,44-C,45-C,46-C,47-A,48-C,49-A,50-A,51-C,52-A,53-C,54-C,55-D,56-A,57-C,58-B,59-B,60-A,61-C,62-C,63-D,64-A,65-A,66-C,67-B,68-C,69-B,70-B,71-C,72-B,73-B,74-C,75-B,76-C,77-A,78-B,79-D,80-B,81-B,82-A,83-C,84-D,85-A,86-D,87-D,88-A,89-X,90-D,91-A,92-B,93-A,94-C,95-A,96-B,97-C,98-D,99-B,100-C'
const keyMap = {}; OFFICIAL.split(',').forEach(p=>{const [n,a]=p.split('-'); keyMap[+n]=a})

const SUBJ_ABBR = { Polity:'POL', History:'HIS', Geography:'GEO', Economy:'ECO', Environment:'ENV', SciTech:'SCI', CurrentAffairs:'CA' }
function fmt(text){
  if (/Match List I with List II/i.test(text)) return 'match_pairs'
  if (/how many of the above/i.test(text)) return 'statements_count'
  return 'single'
}
function slug(s){ return s.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'') }

// verify answers vs official key
let mismatch = []
for (const q of D){ if (keyMap[q.n] !== 'X' && q.a !== keyMap[q.n]) mismatch.push(`Q${q.n}: data=${q.a} key=${keyMap[q.n]}`) }
console.log('count:', D.length)
console.log('answer mismatches vs official key:', mismatch.length ? mismatch.join(' | ') : 'NONE')
const incomplete = D.filter(q=>q.o.length!==4 || !q.q || !q.a)
console.log('incomplete questions:', incomplete.map(q=>q.n).join(',')||'none')

const questions = D.map(q => ({
  question_id: `P2026GS-${String(q.n).padStart(3,'0')}`,
  num: q.n,
  subject: q.s,
  topic: q.t,
  subtopic: `UPSC 2026 Prelims GS-I — Q${q.n}`,
  format: fmt(q.q),
  difficulty: q.d || 'Medium',
  expected_time_sec: q.d === 'Hard' ? 95 : q.d === 'Easy' ? 50 : 75,
  text: q.q,
  options: { A: q.o[0], B: q.o[1], C: q.o[2], D: q.o[3] },
  answer: q.a,
  explanation: q.x,
  elimination_path: q.q.includes('1.') || q.q.includes('I.')
    ? 'Mark each statement true/false first, then eliminate every option that contains a statement you can rule out.'
    : 'Eliminate the clearly wrong options first, then choose between what remains.',
  diagnoses: [slug(q.s), slug(q.t), '2026', 'official-paper', ...(keyMap[q.n]==='X'?['dropped-by-upsc']:[])],
}))

const out = {
  paper: 1,
  title: 'UPSC Civil Services Prelims 2026 — General Studies Paper I (Official)',
  source: 'official_upsc_2026_prelims_gs1',
  questions,
}
fs.writeFileSync('data/question-bank/paper-2026-gs.json', JSON.stringify(out, null, 2))
console.log('wrote data/question-bank/paper-2026-gs.json with', questions.length, 'questions')
